custom_css:
.fca_eoi_layout_1 div.fca_eoi_layout_inputs_wrapper{
    border-top: 0px solid #dbdbdb !important;
    border-bottom: 0px solid #dbdbdb !important;
}
.feedbackSec .jet-tabs__control::after {
    content: "";
    content: "\f061";
    font-family: 'FontAwesome';
    right: 0;
    left: auto;
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    color: #FECE00;
    font-size: 28px;
}
.jet-tabs__control {
position: relative;
    
}
.elementor-accordion .elementor-accordion-item {
    border: 1px solid #d4d4d4;
    border-width: 0px 0px 1px 0px;
}
.elementor-accordion .elementor-tab-content {
    border-top: 0;
}
.txt2 {
    margin-top: 100px;
}
.txt3 {
  margin-top: 220px;
}
@media only screen and (max-width: 768px)  {
.txt2 {
  margin-top: 150px;
}
.txt3 {
  margin-top: 100%;
}
.feedbackSec .jet-tabs__control::after {
    top: 40%;
}
}

@media only screen and (max-width: 767px)  {
.txt2 {
    margin-top: 0px;
}
.txt3 {
    margin-top: 0px;
}

.feedbackSec .jet-tabs__control::after {
    top: 40%;
}
}
@media only screen and (max-width: 600px)  {
    .txt2 {
    margin-top: 0px;
}
.txt3 {
  margin-top: 0px;
}
}
